import type KnowledgeGraphSublayer from "../../layers/knowledgeGraph/KnowledgeGraphSublayer.js";
import type FeatureLikeLayerView from "./FeatureLikeLayerView.js";

/**
 * Represents the [LayerView](https://developers.arcgis.com/javascript/latest/references/core/views/layers/LayerView/) of a [KnowledgeGraphSublayer](https://developers.arcgis.com/javascript/latest/references/core/layers/knowledgeGraph/KnowledgeGraphSublayer/)
 * after it has been added to a [Map](https://developers.arcgis.com/javascript/latest/references/core/Map/).
 *
 * The KnowledgeGraphSublayerView is responsible for rendering a [KnowledgeGraphSublayer's](https://developers.arcgis.com/javascript/latest/references/core/layers/knowledgeGraph/KnowledgeGraphSublayer/)
 * features as [graphics](https://developers.arcgis.com/javascript/latest/references/core/Graphic/) in the [View](https://developers.arcgis.com/javascript/latest/references/core/views/View/).
 *
 * @since 4.11
 * @see [KnowledgeGraphSublayer](https://developers.arcgis.com/javascript/latest/references/core/layers/knowledgeGraph/KnowledgeGraphSublayer/)
 */
export default abstract class KnowledgeGraphSublayerView extends FeatureLikeLayerView {
  /** The layer being viewed. */
  get layer(): KnowledgeGraphSublayer;
}